import MathFin.Binomial.Model

open MathFin

/-- Single-period binomial: the replicating portfolio cost equals the
    risk-neutral expected discounted payoff. -/
theorem binomial_replication_cost {S_0 u d r V_u V_d : ℝ}
    (hS_0 : 0 < S_0) (h : BinomialNoArb u d r) :
    let Δ : ℝ := (V_u - V_d) / (S_0 * (u - d))
    let B : ℝ := Real.exp (-r) * (u * V_d - d * V_u) / (u - d)
    Δ * S_0 + B = binomialOptionPriceOnePeriod u d r V_u V_d :=
  MathFin.replicating_portfolio_cost hS_0 h

/-- Single-period binomial: the replicating portfolio pays V_u in the up state. -/
theorem binomial_replication_up {S_0 u d r V_u V_d : ℝ}
    (hS_0 : 0 < S_0) (h : BinomialNoArb u d r) :
    let Δ : ℝ := (V_u - V_d) / (S_0 * (u - d))
    let B : ℝ := Real.exp (-r) * (u * V_d - d * V_u) / (u - d)
    Δ * (S_0 * u) + B * Real.exp r = V_u :=
  MathFin.replicating_payoff_up hS_0 h

/-- Single-period binomial: the replicating portfolio pays V_d in the down state. -/
theorem binomial_replication_down {S_0 u d r V_u V_d : ℝ}
    (hS_0 : 0 < S_0) (h : BinomialNoArb u d r) :
    let Δ : ℝ := (V_u - V_d) / (S_0 * (u - d))
    let B : ℝ := Real.exp (-r) * (u * V_d - d * V_u) / (u - d)
    Δ * (S_0 * d) + B * Real.exp r = V_d :=
  MathFin.replicating_payoff_down hS_0 h
